proof fn phi_1_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_2_always_propagate_suffix_composition(ex: Execution<int>, p: TempPred<int>, i: nat, j: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i).suffix(j)),
{
    always_propagate_forwards::<int>(ex, p, i);
    always_unfold::<int>(ex.suffix(i), p);
}

proof fn phi_3_always_double_unfold_to_bare(ex: Execution<int>, p: TempPred<int>, i: nat, j: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i).suffix(j)),
{
    always_double::<int>(ex, p);
    always_unfold::<int>(ex, always(p));
    always_unfold::<int>(ex.suffix(i), p);
}

proof fn phi_4_always_propagate_unbounded(ex: Execution<int>, p: TempPred<int>)
    requires
        always(p).satisfied_by(ex),
    ensures
        forall |i: nat, j: nat| p.satisfied_by(#[trigger] ex.suffix(i).suffix(j)),
{
    assert forall |i: nat, j: nat| p.satisfied_by(#[trigger] ex.suffix(i).suffix(j)) by {
        always_propagate_forwards::<int>(ex, p, i);
        always_unfold::<int>(ex.suffix(i), p);
    };
}

proof fn phi_5_always_propagate_zero_redundant(ex: Execution<int>, p: TempPred<int>)
    requires
        always(p).satisfied_by(ex),
    ensures
        always(p).satisfied_by(ex.suffix(0)),
{
    always_propagate_forwards::<int>(ex, p, 0);
}
